html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Rain Effect</title>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/tailwindcss/2.2.19/tailwind.css">
</head>
<body>
    <div class="h-screen w-screen flex justify-center items-center bg-gray-300">
        <div class="w-2/3 bg-white shadow-md p-4">
            <div class="relative h-screen" id="rain-container"></div>
            <button class="mt-4 mb-4 bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded" id="restart-button">Restart</button>
        </div>
    </div>
    <script>
    let rainDrops = [];
    let timerInterval;

    function createRainDrop() {
        const rainDrop = document.createElement('div');
        rainDrop.style.width = '10px';
        rainDrop.style.height = '10px';
        rainDrop.style.background = 'rgb(0, 0, 0)';
        rainDrop.style.borderRadius = '50%';
        rainDrop.style.position = 'absolute';

        const randomX = Math.floor(Math.random() * window.innerWidth);
        const randomY = Math.floor(Math.random() * -window.innerHeight);

        rainDrop.style.top = `${randomY}px`;
        rainDrop.style.left = `${randomX}px`;

        rainContainer.appendChild(rainDrop);
        rainDrops.push(rainDrop);

        return rainDrop;
    }

    const rainContainer = document.getElementById('rain-container');
    const restartButton = document.getElementById('restart-button');

    function animateRain() {
        requestAnimationFrame(animateRain);
        rainDrops.forEach((rainDrop, index) => {
            rainDrop.style.top = `${parseInt(rainDrop.style.top) + 5}px`;

            if (parseInt(rainDrop.style.top) > window.innerHeight) {
                rainContainer.removeChild(rainDrop);
                rainDrops.splice(index, 1);
            }
        });
    }

    restartButton.addEventListener('click', () => {
        rainDrops.forEach(rainDrop => rainContainer.removeChild(rainDrop));
        rainDrops = [];
        requestAnimationFrame(animateRain);
    });

    timerInterval = setInterval(() => {
        createRainDrop();
    }, 100);
    </script>
</body>
</html>
